'use client';

import { useMemo } from 'react';
import { CapacitySettings } from '@/actions/capacity';
import { 
  format, 
  startOfToday, 
  startOfWeek, 
  endOfWeek, 
  addWeeks, 
  differenceInDays,
  isBefore,
  isAfter,
  parseISO
} from 'date-fns';
import { Clock, Users, Activity, Lightbulb, CalendarDays, AlertTriangle, Play, Calendar } from 'lucide-react';
import { cn } from '@/lib/utils';

interface Project {
  id: number;
  workguruId: string;
  projectNumber: string;
  name: string;
  budgetHours: number;
  actualHours: number;
  remainingHours: number;
  deliveryDate: Date | null;
  projectManager: string | null;
  rawStatus: string;
  client: { name: string } | null;
}

interface ProductionClientViewProps {
  initialSettings: CapacitySettings;
  activeProjects: Project[];
}

const formatHours = (value: number) => {
    return new Intl.NumberFormat('en-AU').format(Math.round(value)) + 'h';
};

export default function ProductionClientView({ initialSettings, activeProjects }: ProductionClientViewProps) {
    const today = startOfToday();

    // Group Projects
    const groupedProjects = useMemo(() => {
        const buckets = {
            overdue: [] as Project[],
            thisWeek: [] as Project[],
            next2Weeks: [] as Project[],
            future: [] as Project[],
            unscheduled: [] as Project[]
        };

        const weekStart = startOfWeek(today, { weekStartsOn: 1 }); // Monday start
        const weekEnd = endOfWeek(today, { weekStartsOn: 1 });
        const twoWeeksEnd = addWeeks(weekEnd, 2);

        activeProjects.forEach(p => {
            if (!p.deliveryDate) {
                buckets.unscheduled.push(p);
                return;
            }

            const dDate = new Date(p.deliveryDate);

            if (isBefore(dDate, today)) { // strictly < today
                buckets.overdue.push(p);
            } else if (isBefore(dDate, weekStart)) { // Missed this week start but not today? Unlikely if using startOfToday
                buckets.overdue.push(p);
            } else if (!isAfter(dDate, weekEnd)) {
                buckets.thisWeek.push(p);
            } else if (!isAfter(dDate, twoWeeksEnd)) {
                buckets.next2Weeks.push(p);
            } else {
                buckets.future.push(p);
            }
        });

        // Sort each bucket: Primary: Due Date ASC (put oldest first), Secondary: Remaining Hours DESC
        const sortFn = (a: Project, b: Project) => {
            if (!a.deliveryDate && !b.deliveryDate) return b.remainingHours - a.remainingHours;
            if (!a.deliveryDate) return 1;
            if (!b.deliveryDate) return -1;

            const dateDiff = new Date(a.deliveryDate).getTime() - new Date(b.deliveryDate).getTime();
            if (dateDiff === 0) {
                return b.remainingHours - a.remainingHours;
            }
            return dateDiff;
        };

        buckets.overdue.sort(sortFn);
        buckets.thisWeek.sort(sortFn);
        buckets.next2Weeks.sort(sortFn);
        buckets.future.sort(sortFn);
        buckets.unscheduled.sort(sortFn);

        return buckets;
    }, [activeProjects, today]);

    // Shop Load Analysis (Next 8 Weeks)
    const HORIZON_WEEKS = 8;
    const weeklyLoad = useMemo(() => {
        const weeks = [];
        const currentCapacity = initialSettings.staff * initialSettings.hoursPerWeek * initialSettings.efficiency;
        let runningStart = startOfWeek(today, { weekStartsOn: 1 });

        for (let i = 0; i < HORIZON_WEEKS; i++) {
            const wStart = runningStart;
            const wEnd = endOfWeek(wStart, { weekStartsOn: 1 });

            // Demand: projects due in this week
            const projectsInWeek = activeProjects.filter(p => {
                if (!p.deliveryDate) return false;
                const dDate = new Date(p.deliveryDate);
                return (isAfter(dDate, wStart) || dDate.getTime() === wStart.getTime()) 
                       && (isBefore(dDate, wEnd) || dDate.getTime() === wEnd.getTime());
            });

            const demand = projectsInWeek.reduce((acc, p) => acc + p.remainingHours, 0);

            weeks.push({
                weekStart: wStart,
                weekEnd: wEnd,
                demand,
                capacity: currentCapacity,
                available: currentCapacity - demand,
                projectsCount: projectsInWeek.length,
                projects: projectsInWeek
            });

            runningStart = addWeeks(runningStart, 1);
        }
        return weeks;
    }, [activeProjects, initialSettings, today]);

    return (
        <div className="space-y-8">
            {/* Top Analysis Cards */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* Shop Load Analysis */}
                <div className="lg:col-span-2 bg-white dark:bg-slate-900 rounded-2xl border border-slate-200/60 dark:border-slate-800/60 shadow-sm overflow-hidden flex flex-col">
                    <div className="p-5 border-b border-slate-200/60 dark:border-slate-800/60 flex justify-between items-center bg-slate-50/50 dark:bg-slate-800/20">
                        <div>
                            <h2 className="text-sm font-bold text-slate-900 dark:text-white uppercase tracking-widest flex items-center gap-2">
                                <Activity className="h-4 w-4 text-emerald-500" />
                                Shop Load Analysis
                            </h2>
                            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-wider mt-1 flex items-center gap-1">
                                <Lightbulb className="h-3 w-3 text-amber-500" />
                                Demand based on delivery week. Future iterations may distribute remaining hours across weeks.
                            </p>
                        </div>
                    </div>
                    <div className="overflow-x-auto flex-1 p-0">
                        <table className="w-full text-left text-sm whitespace-nowrap">
                            <thead className="bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200/60 dark:border-slate-700/60 text-[10px] uppercase tracking-widest font-bold text-slate-400">
                                <tr>
                                    <th className="px-5 py-3">Week Of</th>
                                    <th className="px-4 py-3 text-center">Projects</th>
                                    <th className="px-5 py-3 text-right">Demand</th>
                                    <th className="px-5 py-3 text-right">Capacity</th>
                                    <th className="px-5 py-3 text-right">Available</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-slate-100 dark:divide-slate-800/60">
                                {weeklyLoad.map((w, i) => {
                                    const isCurrentWeek = i === 0;
                                    const isOverloaded = w.available < 0;
                                    const isAtRisk = w.available >= 0 && w.available <= w.capacity * 0.1;

                                    return (
                                        <tr key={i} className={cn("hover:bg-slate-50/50 dark:hover:bg-slate-800/30 transition-colors", isCurrentWeek ? "bg-slate-50/80 dark:bg-slate-800/40" : "")}>
                                            <td className="px-5 py-3">
                                                <div className="flex gap-2 items-center">
                                                    <span className={cn("font-bold text-sm", isCurrentWeek ? "text-brand" : "text-slate-900 dark:text-white")}>
                                                        {format(w.weekStart, 'MMM d')} - {format(w.weekEnd, 'MMM d')}
                                                    </span>
                                                    {isCurrentWeek && <span className="px-1.5 py-0.5 rounded text-[9px] font-black uppercase text-brand bg-brand/10 tracking-widest">Current</span>}
                                                </div>
                                            </td>
                                            <td className="px-4 py-3 text-center text-xs font-bold text-slate-500">{w.projectsCount}</td>
                                            <td className="px-5 py-3 text-right font-bold text-slate-900 dark:text-white tabular-nums">{formatHours(w.demand)}</td>
                                            <td className="px-5 py-3 text-right font-bold text-slate-500 tabular-nums">{formatHours(w.capacity)}</td>
                                            <td className={cn(
                                                "px-5 py-3 text-right font-black tabular-nums text-base",
                                                isOverloaded ? "text-red-500" : isAtRisk ? "text-orange-500" : "text-emerald-500"
                                            )}>
                                                {formatHours(w.available)}
                                            </td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    </div>
                </div>

                {/* Timeline Visualization */}
                <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200/60 dark:border-slate-800/60 shadow-sm flex flex-col overflow-hidden">
                    <div className="p-5 border-b border-slate-200/60 dark:border-slate-800/60 bg-slate-50/50 dark:bg-slate-800/20">
                        <h2 className="text-sm font-bold text-slate-900 dark:text-white uppercase tracking-widest flex items-center gap-2">
                             <CalendarDays className="h-4 w-4 text-indigo-500" />
                             Delivery Density
                        </h2>
                        <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mt-1"># Projects due per week</p>
                    </div>
                    <div className="p-5 flex-1 flex items-end gap-2 overflow-x-auto custom-scrollbar">
                        {weeklyLoad.map((w, i) => {
                            const maxProjects = Math.max(...weeklyLoad.map(wl => wl.projectsCount), 1);
                            const heightPercent = (w.projectsCount / maxProjects) * 100;
                            const isOverloaded = w.available < 0;

                            return (
                                <div key={i} className="flex-1 flex flex-col items-center justify-end h-full gap-2 min-w-[32px] group relative">
                                    <span className="text-[10px] font-bold text-slate-400 mb-1 opacity-0 group-hover:opacity-100 transition-opacity absolute -top-4">{w.projectsCount}</span>
                                    <div 
                                        className={cn(
                                            "w-full rounded-sm transition-all duration-500",
                                            isOverloaded ? "bg-red-500/80" : "bg-indigo-400/80 dark:bg-indigo-500/80",
                                            w.projectsCount === 0 ? "h-1 bg-slate-100 dark:bg-slate-800" : "hover:brightness-110"
                                        )}
                                        style={{ height: w.projectsCount > 0 ? \`\${Math.max(10, heightPercent)}%\` : '4px' }}
                                    />
                                    <span className="text-[9px] font-bold text-slate-500 rotate-[-45deg] origin-top-left -ml-2 mt-2">{format(w.weekStart, 'MMM d')}</span>
                                </div>
                            );
                        })}
                    </div>
                </div>
            </div>

            {/* Main Execution View: Time Buckets */}
            <div className="space-y-6">
                <BucketSection title="Overdue" projects={groupedProjects.overdue} type="overdue" today={today} />
                <BucketSection title="Due This Week" projects={groupedProjects.thisWeek} type="soon" today={today} />
                <BucketSection title="Due Next 2 Weeks" projects={groupedProjects.next2Weeks} type="upcoming" today={today} />
                <BucketSection title="Future" projects={groupedProjects.future} type="normal" today={today} />
                <BucketSection title="Unscheduled" projects={groupedProjects.unscheduled} type="unscheduled" today={today} />
            </div>
        </div>
    );
}

function BucketSection({ title, projects, type, today }: { title: string, projects: Project[], type: 'overdue'|'soon'|'upcoming'|'normal'|'unscheduled', today: Date }) {
    if (projects.length === 0) return null;

    const getHeaderStyles = () => {
        if (type === 'overdue') return "text-red-700 dark:text-red-400 bg-red-50 dark:bg-red-500/10 border-red-200 dark:border-red-500/20";
        if (type === 'soon') return "text-orange-700 dark:text-orange-400 bg-orange-50 dark:bg-orange-500/10 border-orange-200 dark:border-orange-500/20";
        if (type === 'upcoming') return "text-blue-700 dark:text-blue-400 bg-blue-50 dark:bg-blue-500/10 border-blue-200 dark:border-blue-500/20";
        if (type === 'unscheduled') return "text-slate-500 bg-slate-100 dark:bg-slate-800/80 border-slate-200 dark:border-slate-700";
        return "text-slate-900 dark:text-white bg-slate-50 dark:bg-slate-800/40 border-slate-200 dark:border-slate-800/60";
    };

    return (
        <div className="block">
            <div className={cn("inline-flex items-center gap-2 px-4 py-2 rounded-t-xl border-t border-l border-r border-b-0 font-bold text-sm tracking-wide uppercase shadow-sm relative z-10", getHeaderStyles())}>
                {type === 'overdue' && <AlertTriangle className="h-4 w-4" />}
                {type === 'soon' && <Play className="h-4 w-4" />}
                {type === 'unscheduled' && <Calendar className="h-4 w-4" />}
                {title}
                <span className="ml-2 px-2 py-0.5 rounded-md bg-white/50 dark:bg-black/20 text-xs">{projects.length}</span>
            </div>

            <div className="bg-white dark:bg-slate-900 border border-slate-200/60 dark:border-slate-800/60 rounded-xl rounded-tl-none overflow-hidden shadow-sm relative -mt-[1px] z-0">
                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left whitespace-nowrap">
                        <thead className="bg-slate-50/50 dark:bg-slate-800/50 border-b border-slate-200/60 dark:border-slate-700/60 text-[10px] uppercase tracking-widest font-bold text-slate-400">
                            <tr>
                                <th className="px-4 py-3 w-10"></th>
                                <th className="px-4 py-3">Project</th>
                                <th className="px-4 py-3 font-semibold">Client</th>
                                <th className="px-4 py-3 font-semibold">PM</th>
                                <th className="px-4 py-3">Due Date</th>
                                <th className="px-4 py-3 text-right">Remaining Hrs</th>
                                <th className="px-4 py-3 w-48">Progress</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100 dark:divide-slate-800/60">
                            {projects.map((p) => {
                                const percent = p.budgetHours > 0 ? (p.actualHours / p.budgetHours) * 100 : 0;
                                const displayPercent = Math.min(100, Math.max(0, percent));

                                const isOverdue = p.deliveryDate && isBefore(new Date(p.deliveryDate), today);
                                const isDueSoon = p.deliveryDate && isBefore(new Date(p.deliveryDate), addDays(today, 14)) && !isOverdue;
                                const isHighPercent = percent >= 80 && p.rawStatus !== 'Completed';

                                const daysRemaining = p.deliveryDate ? differenceInDays(new Date(p.deliveryDate), today) : null;

                                return (
                                    <tr key={p.id} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/30 transition-colors group">
                                        <td className="px-4 py-3">
                                            <div className="flex gap-1.5 flex-col items-start w-10">
                                                {isOverdue && <span className="w-2 h-2 rounded-full bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.6)]" title="Overdue" />}
                                                {isDueSoon && <span className="w-2 h-2 rounded-full bg-orange-400 shadow-[0_0_8px_rgba(251,146,60,0.6)]" title="Due Soon" />}
                                                {isHighPercent && <span className="w-2 h-2 rounded-full bg-amber-300 shadow-[0_0_8px_rgba(252,211,77,0.6)]" title="High Usage >= 80%" />}
                                            </div>
                                        </td>
                                        <td className="px-4 py-3">
                                            <div className="flex flex-col gap-0.5">
                                                <span className="font-bold text-xs text-slate-500">{p.projectNumber}</span>
                                                <span className="font-bold text-slate-900 dark:text-white truncate max-w-[250px]">{p.name}</span>
                                            </div>
                                        </td>
                                        <td className="px-4 py-3">
                                            <span className="text-xs font-bold text-slate-600 dark:text-slate-300">{p.client?.name || 'Unknown'}</span>
                                        </td>
                                        <td className="px-4 py-3">
                                            <span className="text-xs font-bold text-slate-500">{p.projectManager || 'Unassigned'}</span>
                                        </td>
                                        <td className="px-4 py-3">
                                            {p.deliveryDate ? (
                                                <div className="flex flex-col gap-0.5 items-start">
                                                    <span className={cn(
                                                        "text-sm font-bold",
                                                        isOverdue ? "text-red-600 dark:text-red-400" : "text-slate-900 dark:text-white"
                                                    )}>
                                                        {format(new Date(p.deliveryDate), 'MMM d, yyyy')}
                                                    </span>
                                                    {daysRemaining !== null && (
                                                        <span className={cn(
                                                            "text-[10px] uppercase font-bold tracking-wider px-1.5 py-0.5 rounded-sm",
                                                            daysRemaining < 0 ? "bg-red-100 text-red-700 dark:bg-red-500/20 dark:text-red-400" :
                                                            daysRemaining <= 14 ? "bg-orange-100 text-orange-700 dark:bg-orange-500/20 dark:text-orange-400" :
                                                            "text-slate-400"
                                                        )}>
                                                            {daysRemaining < 0 ? \`\${Math.abs(daysRemaining)} days late\` :
                                                             daysRemaining === 0 ? 'Due today' : \`\${daysRemaining} days left\`}
                                                        </span>
                                                    )}
                                                </div>
                                            ) : (
                                                <span className="text-xs font-medium italic text-slate-400">None set</span>
                                            )}
                                        </td>
                                        <td className="px-4 py-3 text-right">
                                            <span className="text-base font-black tabular-nums text-slate-800 dark:text-slate-200">{formatHours(p.remainingHours)}</span>
                                        </td>
                                        <td className="px-4 py-3">
                                            <div className="flex items-center gap-3">
                                                <div className="flex-1 h-2 flex bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden shadow-inner isolate">
                                                    <div 
                                                        className={cn(
                                                            "h-full transition-all duration-700 ease-out",
                                                            isHighPercent ? "bg-amber-400" : "bg-emerald-400"
                                                        )} 
                                                        style={{ width: \`\${displayPercent}%\` }} 
                                                    />
                                                </div>
                                                <span className={cn(
                                                    "text-[10px] font-bold w-10 text-right tabular-nums",
                                                    isHighPercent ? "text-amber-500" : "text-slate-500"
                                                )}>
                                                    {Math.round(percent)}%
                                                </span>
                                            </div>
                                        </td>
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

'use client';

import { useState, useMemo, useEffect } from 'react';
import { CapacitySettings, updateCapacitySettings } from '@/actions/capacity';
import { format, addMonths, startOfMonth, parseISO } from 'date-fns';
import { AlertTriangle, TrendingDown, TrendingUp, Users, Activity, Save, Loader2, Info, Lightbulb, PieChart, Layers } from 'lucide-react';
import { cn } from '@/lib/utils';
import { toast } from 'sonner';

interface Project {
  id: number;
  workguruId: string;
  projectNumber: string;
  name: string;
  budgetHours: number;
  actualHours: number;
  remainingHours: number;
  deliveryDate: Date | null;
  projectManager: string | null;
}

interface CapacityClientViewProps {
  initialSettings: CapacitySettings;
  activeProjects: Project[];
  initialHorizon: number; // Ignored for Phase 4 since we track local state
}

const formatHours = (value: number) => {
    return new Intl.NumberFormat('en-AU').format(Math.round(value)) + 'h';
};

type TimeRangeType = '3' | '6' | '12' | 'custom';

export default function CapacityClientView({ initialSettings, activeProjects }: CapacityClientViewProps) {
  const [settings, setSettings] = useState<CapacitySettings>(initialSettings);
  const [isSaving, setIsSaving] = useState(false);

  const [timeRange, setTimeRange] = useState<TimeRangeType>('6');
  const [customStart, setCustomStart] = useState<string>(format(new Date(), 'yyyy-MM'));
  const [customEnd, setCustomEnd] = useState<string>(format(addMonths(new Date(), 5), 'yyyy-MM'));

  const [selectedMonth, setSelectedMonth] = useState<string | null>(null);

  const handleSave = async () => {
    try {
      setIsSaving(true);
      await updateCapacitySettings(settings);
      toast.success('Capacity settings updated');
    } catch (e: any) {
      toast.error(e.message || 'Failed to update settings');
    } finally {
      setIsSaving(false);
    }
  };

  const currentCapacity = settings.staff * settings.hoursPerWeek * settings.weeksPerMonth * settings.efficiency;

  // Generate continuous months based on selector
  const months = useMemo(() => {
    const list = [];
    if (timeRange === 'custom') {
       let curr = parseISO(`${customStart}-01`);
       const end = parseISO(`${customEnd}-01`);
       // Guard against infinite loop if invalid
       let count = 0;
       while (curr <= end && count < 60) {
          list.push(format(curr, 'yyyy-MM'));
          curr = addMonths(curr, 1);
          count++;
       }
       if (list.length === 0) list.push(format(new Date(), 'yyyy-MM')); // Fallback
    } else {
       const horizon = parseInt(timeRange);
       const now = startOfMonth(new Date());
       for (let i = 0; i < horizon; i++) {
          list.push(format(addMonths(now, i), 'yyyy-MM'));
       }
    }
    return list;
  }, [timeRange, customStart, customEnd]);

  useEffect(() => {
    if (!selectedMonth || !months.includes(selectedMonth)) {
       setSelectedMonth(months[0] || null);
    }
  }, [months, selectedMonth]);

  // Aggregate Data
  const monthlyData = useMemo(() => {
    const data: Record<string, { budget: number; actual: number; remaining: number; projects: Project[] }> = {};
    months.forEach(m => data[m] = { budget: 0, actual: 0, remaining: 0, projects: [] });

    activeProjects.forEach(p => {
        if (!p.deliveryDate) return; 
        const m = format(new Date(p.deliveryDate), 'yyyy-MM');
        if (data[m]) {
            data[m].budget += p.budgetHours;
            data[m].actual += p.actualHours;
            data[m].remaining += p.remainingHours;
            data[m].projects.push(p);
        }
    });

    return data;
  }, [activeProjects, months]);

  // Summary Metrics
  const totalCapacity = currentCapacity * months.length;
  const totalPlanned = months.reduce((acc, m) => acc + monthlyData[m].remaining, 0);
  const netAvailable = totalCapacity - totalPlanned;
  const overloadedMonthsCount = months.filter(m => currentCapacity - monthlyData[m].remaining < 0).length;

  // Intelligent Insight
  const insightText = useMemo(() => {
      const overloaded = months.find(m => currentCapacity - monthlyData[m].remaining < 0);
      if (overloaded) {
          const topReqs = [...monthlyData[overloaded].projects]
                .sort((a,b) => b.remainingHours - a.remainingHours)
                .slice(0, 2);
          const names = topReqs.map(p => `"${p.name}"`).join(' and ');
          return `${format(parseISO(`${overloaded}-01`), 'MMMM')} is overloaded, primarily driven by ${names || 'multiple smaller projects'}.`;
      }

      const atRisk = months.find(m => (currentCapacity - monthlyData[m].remaining) <= currentCapacity * 0.1);
      if (atRisk) {
          return `Capacity tightens in ${format(parseISO(`${atRisk}-01`), 'MMMM')}. Consider spacing out deliverables.`;
      }

      return `Forward capacity is healthy with ample buffer across the next ${months.length} months.`;
  }, [months, monthlyData, currentCapacity]);

  // PM Load Breakdown
  const pmLoad = useMemo(() => {
    const load: Record<string, number> = {};
    months.forEach(m => {
        monthlyData[m].projects.forEach(p => {
            const pm = p.projectManager || 'Unassigned';
            load[pm] = (load[pm] || 0) + p.remainingHours;
        });
    });

    return Object.entries(load)
      .sort((a, b) => b[1] - a[1]) // Descending
      .filter(([_, hours]) => hours > 0);
  }, [monthlyData, months]);

  return (
    <div className="space-y-6">
      {/* Dynamic Time Selector & Insight */}
      <div className="flex flex-col xl:flex-row gap-4 justify-between items-start xl:items-center bg-slate-50 dark:bg-slate-900/40 p-3 rounded-2xl border border-slate-200/60 dark:border-slate-800/60">
         <div className="flex items-center gap-3">
             <div className="flex p-1 bg-white dark:bg-slate-950 rounded-xl shadow-sm border border-slate-200/50 dark:border-slate-800/50">
                 {['3', '6', '12', 'custom'].map((tr) => (
                    <button 
                       key={tr}
                       onClick={() => setTimeRange(tr as TimeRangeType)}
                       className={cn("px-4 py-1.5 text-xs font-bold rounded-lg transition-all capitalize", timeRange === tr ? "bg-slate-900 text-white dark:bg-slate-700 shadow-sm" : "text-slate-500 hover:text-slate-700 dark:hover:text-slate-300")}
                    >
                        {tr === 'custom' ? 'Custom' : `${tr} Mo`}
                    </button>
                 ))}
             </div>
             {timeRange === 'custom' && (
                 <div className="flex items-center gap-2">
                     <input type="month" value={customStart} onChange={(e) => setCustomStart(e.target.value)} className="text-xs bg-white dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-lg px-2 py-1" />
                     <span className="text-xs text-slate-400">to</span>
                     <input type="month" value={customEnd} onChange={(e) => setCustomEnd(e.target.value)} className="text-xs bg-white dark:bg-slate-950 border border-slate-200 dark:border-slate-800 rounded-lg px-2 py-1" />
                 </div>
             )}
         </div>

         {/* Simple Insight */}
         <div className="flex items-center gap-3 px-4 py-2 bg-indigo-50 dark:bg-indigo-500/10 rounded-xl border border-indigo-100 dark:border-indigo-500/20 text-indigo-700 dark:text-indigo-300">
             <Lightbulb className="h-4 w-4 shrink-0" />
             <p className="text-xs font-semibold">{insightText}</p>
         </div>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
          <SummaryCard title="Total Demand" value={formatHours(totalPlanned)} subtitle={`${months.length} mo horizon`} icon={<PieChart />} />
          <SummaryCard title="Total Capacity" value={formatHours(totalCapacity)} subtitle={`Team of ${settings.staff}`} icon={<Users />} />
          <SummaryCard title="Net Available" value={formatHours(netAvailable)} subtitle="Capacity - Demand" highlight={netAvailable < 0 ? 'red' : 'green'} icon={<Layers />} />
          <SummaryCard title="Risk Periods" value={overloadedMonthsCount} suffix="mos" subtitle="Overloaded months" highlight={overloadedMonthsCount > 0 ? 'orange' : 'neutral'} icon={<AlertTriangle />} />
      </div>

      {/* Main Grid: Data & Sidebars */}
      <div className="grid grid-cols-1 xl:grid-cols-12 gap-6">

          {/* Table & Drivers (Left 9 columns) */}
          <div className="xl:col-span-9 space-y-6">
              <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200/60 dark:border-slate-800/60 shadow-sm overflow-hidden">
                  <div className="overflow-x-auto">
                      <table className="w-full text-sm text-left">
                          <thead className="bg-slate-50/50 dark:bg-slate-800/50 border-b border-slate-200/60 dark:border-slate-700/60 text-[10px] uppercase tracking-widest font-bold text-slate-400">
                              <tr>
                                  <th className="px-5 py-3">Month</th>
                                  <th className="px-5 py-3 text-right">Budget</th>
                                  <th className="px-5 py-3 text-right">Actual</th>
                                  <th className="px-5 py-3 text-right text-slate-700 dark:text-slate-300">Remaining</th>
                                  <th className="px-5 py-3 text-right text-slate-700 dark:text-slate-300">Available</th>
                                  <th className="px-5 py-3 w-[25%] text-left">Capacity Utilization</th>
                              </tr>
                          </thead>
                          <tbody className="divide-y divide-slate-100 dark:divide-slate-800/60">
                              {months.map(m => {
                                  const d = monthlyData[m];
                                  const planned = d.remaining;
                                  const available = currentCapacity - planned;
                                  const percent = currentCapacity > 0 ? (planned / currentCapacity) * 100 : 0;

                                  const isSelected = selectedMonth === m;
                                  const isOverloaded = available < 0;
                                  const isAtRisk = available >= 0 && available <= currentCapacity * 0.1;

                                  const rowClass = cn(
                                      "transition-all cursor-pointer group",
                                      isSelected ? "bg-slate-50 dark:bg-slate-800/80 ring-1 ring-inset ring-slate-200 dark:ring-slate-700" : "hover:bg-slate-50/50 dark:hover:bg-slate-800/30",
                                      isOverloaded && !isSelected ? "bg-red-50/30 dark:bg-red-900/10" : "",
                                      isAtRisk && !isSelected ? "bg-orange-50/30 dark:bg-orange-900/10" : ""
                                  );

                                  return (
                                      <tr key={m} className={rowClass} onClick={() => setSelectedMonth(m)}>
                                          <td className="px-5 py-4 whitespace-nowrap">
                                              <span className={cn(
                                                  "font-bold text-sm",
                                                  isSelected ? "text-brand" : "text-slate-900 dark:text-white"
                                              )}>
                                                  {format(parseISO(`${m}-01`), 'MMM yyyy')}
                                              </span>
                                          </td>
                                          <td className="px-5 py-4 text-right text-xs text-slate-400 tabular-nums">{formatHours(d.budget)}</td>
                                          <td className="px-5 py-4 text-right text-xs text-slate-400 tabular-nums">{formatHours(d.actual)}</td>

                                          {/* Emphasized Fields */}
                                          <td className="px-5 py-4 text-right font-bold text-slate-900 dark:text-white tabular-nums text-base">{formatHours(d.remaining)}</td>
                                          <td className={cn(
                                              "px-5 py-4 text-right font-bold tabular-nums text-base relative group/row-info",
                                              isOverloaded ? "text-red-500" : isAtRisk ? "text-orange-500" : "text-emerald-600 dark:text-emerald-400"
                                          )}>
                                              {formatHours(available)}
                                              {/* Contextual Tooltip */}
                                              <div className="absolute bottom-full right-0 mb-2 p-3 bg-slate-900 text-white text-[10px] font-bold rounded-xl opacity-0 invisible group-hover/row-info:opacity-100 group-hover/row-info:visible transition-all whitespace-nowrap shadow-xl border border-white/10 z-[60]">
                                                  <div className="flex flex-col gap-1">
                                                      <p className="text-brand">Calculation</p>
                                                      <p className="text-slate-300 font-medium normal-case tracking-normal">Available = Capacity - Planned</p>
                                                      <hr className="border-white/10 my-1" />
                                                      <div className="flex justify-between gap-4 font-mono">
                                                          <span>Capacity:</span>
                                                          <span className="text-white">{formatHours(currentCapacity)}</span>
                                                      </div>
                                                      <div className="flex justify-between gap-4 font-mono">
                                                          <span>Planned:</span>
                                                          <span className="text-white">{formatHours(d.remaining)}</span>
                                                      </div>
                                                  </div>
                                                  <div className="absolute -bottom-1 right-6 w-2 h-2 bg-slate-900 rotate-45 border-r border-b border-white/10" />
                                              </div>
                                          </td>

                                          {/* Visual Risk Bar */}
                                          <td className="px-5 py-4">
                                              <div className="flex items-center gap-3">
                                                  <div className="flex-1 h-3 flex bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden shadow-inner isolate">
                                                      <div 
                                                          className={cn(
                                                              "h-full transition-all duration-700 ease-out",
                                                              isOverloaded ? "bg-red-500" : isAtRisk ? "bg-orange-400" : "bg-emerald-400"
                                                          )} 
                                                          style={{ width: `${Math.min(100, percent)}%` }} 
                                                      />
                                                  </div>
                                                  <span className={cn(
                                                      "text-[10px] font-bold w-10 text-right tabular-nums",
                                                      isOverloaded ? "text-red-600 dark:text-red-400" : "text-slate-500"
                                                  )}>
                                                      {Math.round(percent)}%
                                                  </span>
                                              </div>
                                          </td>
                                      </tr>
                                  );
                              })}
                          </tbody>
                      </table>
                  </div>
              </div>

              {/* Dynamic Top Drivers */}
              {selectedMonth && (
                  <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200/60 dark:border-slate-800/60 p-6 shadow-sm animate-in slide-in-from-bottom-2 duration-300">
                      <div className="flex items-center justify-between mb-6">
                          <h3 className="text-sm font-bold text-slate-900 dark:text-white uppercase tracking-widest flex items-center gap-2">
                             <TrendingUp className="h-4 w-4 text-brand" />
                             Top Drivers • {format(parseISO(`${selectedMonth}-01`), 'MMMM yyyy')}
                          </h3>
                          <span className="text-xs font-bold px-2 py-1 bg-slate-100 dark:bg-slate-800 text-slate-500 rounded-md">
                              Total Demand: {formatHours(monthlyData[selectedMonth].remaining)}
                          </span>
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                          {monthlyData[selectedMonth].projects.length > 0 ? (
                              [...monthlyData[selectedMonth].projects]
                                .sort((a,b) => b.remainingHours - a.remainingHours)
                                .slice(0, 3)
                                .map((p, i) => {
                                    const percentOfTotal = monthlyData[selectedMonth].remaining > 0 
                                      ? (p.remainingHours / monthlyData[selectedMonth].remaining) * 100 
                                      : 0;

                                    return (
                                        <div key={p.id} className="relative p-4 bg-slate-50 dark:bg-slate-800/40 border border-slate-100 dark:border-slate-800/80 rounded-xl group hover:border-brand/30 transition-colors">
                                           <div className="absolute top-0 right-0 p-3 opacity-10 font-black text-4xl italic -mt-2 -mr-1">#{i+1}</div>
                                           <p className="font-bold text-xs text-slate-500 mb-1">{p.projectNumber}</p>
                                           <p className="font-bold text-sm text-slate-900 dark:text-white line-clamp-1 mb-3" title={p.name}>{p.name}</p>

                                           <div className="flex justify-between items-end">
                                               <div>
                                                   <p className="text-[10px] uppercase font-bold text-slate-400 tracking-wider">Remaining</p>
                                                   <p className="font-black text-xl tabular-nums text-slate-700 dark:text-slate-200">{formatHours(p.remainingHours)}</p>
                                               </div>
                                               <div className="text-right">
                                                   <span className="text-xs font-bold text-brand bg-brand/10 px-2 py-1 rounded-md">{percentOfTotal.toFixed(1)}%</span>
                                               </div>
                                           </div>
                                        </div>
                                    );
                                })
                          ) : (
                              <div className="col-span-3 py-8 text-center bg-slate-50 dark:bg-slate-800/20 rounded-xl border border-dashed border-slate-200 dark:border-slate-800">
                                  <p className="text-sm font-medium text-slate-400">No project demand scheduled for this month.</p>
                              </div>
                          )}
                      </div>
                  </div>
              )}
          </div>

          {/* Right Sidebar (Settings + PM Load) */}
          <div className="xl:col-span-3 space-y-6">

              {/* Settings Core */}
              <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200/60 dark:border-slate-800/60 p-5 shadow-sm">
                  <div className="flex items-center justify-between mb-5">
                      <h2 className="text-xs font-bold text-slate-900 dark:text-white uppercase tracking-widest flex items-center gap-2">
                          <SettingsIcon className="h-4 w-4 text-slate-400" />
                          Capacity Factors
                      </h2>
                      <button 
                          onClick={handleSave}
                          disabled={isSaving}
                          className="flex items-center gap-1.5 px-3 py-1.5 bg-brand hover:bg-brand-focus text-white text-[10px] font-bold uppercase tracking-widest rounded-lg transition-all"
                      >
                          {isSaving ? <Loader2 className="h-3 w-3 animate-spin" /> : <Save className="h-3 w-3" />}
                          Save
                      </button>
                  </div>

                  <div className="space-y-4">
                      <div className="grid grid-cols-2 gap-3">
                          <SettingField label="Staff" value={settings.staff} onChange={(v) => setSettings({...settings, staff: v})} step={0.5} min={1} />
                          <SettingField label="Hrs/Wk" value={settings.hoursPerWeek} onChange={(v) => setSettings({...settings, hoursPerWeek: v})} step={1} min={1} />
                      </div>
                      <div className="grid grid-cols-2 gap-3">
                          <SettingField label="Efficiency" value={settings.efficiency} onChange={(v) => setSettings({...settings, efficiency: v})} step={0.05} min={0} max={1} />
                          <SettingField label="Wks/Mo" value={settings.weeksPerMonth} onChange={(v) => setSettings({...settings, weeksPerMonth: v})} step={0.01} min={1} />
                      </div>
                  </div>
              </div>

              {/* PM Load Panel */}
              <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200/60 dark:border-slate-800/60 shadow-sm p-5 flex flex-col h-[500px]">
                  <div className="flex items-center justify-between gap-2 mb-2">
                      <h2 className="text-xs font-bold text-slate-900 dark:text-white uppercase tracking-widest flex items-center gap-2">
                          <Activity className="h-4 w-4 text-indigo-500" />
                          PM Load
                      </h2>
                      <span className="text-[10px] text-slate-400 font-bold uppercase tracking-wider">{months.length} mo</span>
                  </div>
                  <p className="text-xs text-slate-500 mb-6">Aggregate % of total planned workload.</p>

                  <div className="space-y-4 overflow-y-auto pr-2 custom-scrollbar flex-1">
                      {pmLoad.length > 0 ? pmLoad.map(([pm, hours], i) => {
                          const percent = (hours / totalPlanned) * 100;
                          const isTop = i < 2; // Highlight top 2
                          return (
                              <div key={pm} className="space-y-1.5 group p-2 rounded-lg hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                                  <div className="flex justify-between items-center text-xs font-bold">
                                      <span className={cn(
                                          "truncate pr-4 flex items-center gap-2",
                                          isTop ? "text-slate-900 dark:text-white" : "text-slate-600 dark:text-slate-400"
                                      )}>
                                          {isTop && <span className="w-1.5 h-1.5 rounded-full bg-red-500" />}
                                          {pm}
                                      </span>
                                      <div className="text-right">
                                          <span className="text-slate-900 dark:text-white tabular-nums">{formatHours(hours)}</span>
                                          <span className="text-[10px] text-slate-400 ml-1">({percent.toFixed(1)}%)</span>
                                      </div>
                                  </div>
                                  <div className="h-1.5 w-full bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                                      <div 
                                          className={cn(
                                              "h-full rounded-full transition-all duration-1000",
                                              isTop ? "bg-red-500" : "bg-indigo-400"
                                          )}
                                          style={{ width: `${Math.min(100, (hours / (pmLoad[0][1] || 1)) * 100)}%` }} // Scaled relative to highest PM for better visual distinction
                                      />
                                  </div>
                              </div>
                          );
                      }) : (
                          <div className="flex items-center justify-center h-full text-xs font-medium text-slate-400 italic">No PM data available.</div>
                      )}
                  </div>
              </div>
          </div>
      </div>
    </div>
  );
}

// Icon component
function SettingsIcon(props: any) {
    return <svg {...props} xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12.22 2h-.44a2 2 0 0 0-2 2v.18a2 2 0 0 1-1 1.73l-.43.25a2 2 0 0 1-2 0l-.15-.08a2 2 0 0 0-2.73.73l-.22.38a2 2 0 0 0 .73 2.73l.15.1a2 2 0 0 1 1 1.72v.51a2 2 0 0 1-1 1.74l-.15.09a2 2 0 0 0-.73 2.73l.22.38a2 2 0 0 0 2.73.73l.15-.08a2 2 0 0 1 2 0l.43.25a2 2 0 0 1 1 1.73V20a2 2 0 0 0 2 2h.44a2 2 0 0 0 2-2v-.18a2 2 0 0 1 1-1.73l.43-.25a2 2 0 0 1 2 0l.15.08a2 2 0 0 0 2.73-.73l.22-.39a2 2 0 0 0-.73-2.73l-.15-.08a2 2 0 0 1-1-1.74v-.5a2 2 0 0 1 1-1.74l.15-.09a2 2 0 0 0 .73-2.73l-.22-.38a2 2 0 0 0-2.73-.73l-.15.08a2 2 0 0 1-2 0l-.43-.25a2 2 0 0 1-1-1.73V4a2 2 0 0 0-2-2z"/><circle cx="12" cy="12" r="3"/></svg>;
}

function SettingField({ label, value, onChange, min, max, step }: { label: string, value: number, onChange: (v: number) => void, min?: number, max?: number, step?: number }) {
    return (
        <div className="space-y-1">
            <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">{label}</label>
            <input 
              type="number" 
              min={min} max={max} step={step}
              value={value || ''}
              onChange={(e) => onChange(parseFloat(e.target.value) || 0)}
              className="w-full bg-slate-50 dark:bg-slate-950/50 border border-slate-200 dark:border-slate-800 rounded-lg px-2.5 py-1.5 text-xs font-bold font-mono focus:ring-1 focus:ring-brand focus:border-brand transition-all"
            />
        </div>
    );
}

function SummaryCard({ title, value, suffix, subtitle, highlight, icon }: any) {
    return (
        <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200/60 dark:border-slate-800/60 shadow-sm relative overflow-hidden group">
            <div className="absolute -right-4 -top-4 p-6 opacity-[0.03] dark:opacity-5 group-hover:scale-110 transition-transform duration-500 pointer-events-none">
                <div className="w-24 h-24">{icon}</div>
            </div>
            <div className="flex justify-between items-start mb-3">
                <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest">{title}</h3>
                <div className={cn(
                    "p-1.5 rounded-lg border shadow-sm",
                    highlight === 'red' ? "bg-red-50 dark:bg-red-500/10 border-red-200 dark:border-red-500/20 text-red-500" :
